import anthropic

client = anthropic.Anthropic()


def stream_with_error_handling(prompt: str) -> str:
    collected = []
    try:
        with client.messages.stream(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            messages=[{"role": "user", "content": prompt}],
        ) as stream:
            for text in stream.text_stream:
                collected.append(text)
                print(text, end="", flush=True)
        print()  # newline after stream
        return "".join(collected)

    except anthropic.RateLimitError:
        # Stream was cut at mid-point by a rate limit error
        partial = "".join(collected)
        raise RuntimeError(
            f"Stream interrupted by rate limit after {len(partial)} chars"
        )
    except anthropic.InternalServerError as e:
        partial = "".join(collected)
        raise RuntimeError(
            f"Stream interrupted by server error {e.status_code} after {len(partial)} chars"
        ) from e


try:
    result = stream_with_error_handling("List the planets of the solar system.")
except RuntimeError as e:
    print(f"Streaming failed: {e}")

import anthropic
import time
from collections import deque
from enum import Enum

client = anthropic.Anthropic()


class State(Enum):
    CLOSED = "closed"      # normal operation
    OPEN = "open"          # blocking all requests
    HALF_OPEN = "half_open"  # testing recovery


class CircuitBreaker:
    def __init__(
        self,
        failure_threshold: int = 5,
        recovery_timeout: float = 60.0,
        window: int = 10,
    ):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self._failures: deque = deque(maxlen=window)
        self._state = State.CLOSED
        self._opened_at: float = 0.0

    @property
    def state(self) -> State:
        if self._state == State.OPEN:
            if time.monotonic() - self._opened_at >= self.recovery_timeout:
                self._state = State.HALF_OPEN
        return self._state

    def record_success(self) -> None:
        self._failures.append(0)
        if self._state == State.HALF_OPEN:
            self._state = State.CLOSED

    def record_failure(self) -> None:
        self._failures.append(1)
        if sum(self._failures) >= self.failure_threshold:
            self._state = State.OPEN
            self._opened_at = time.monotonic()

    def call(self, prompt: str) -> str:
        if self.state == State.OPEN:
            raise RuntimeError("Circuit breaker OPEN — provider unavailable")
        try:
            resp = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=256,
                messages=[{"role": "user", "content": prompt}],
            )
            self.record_success()
            return resp.content[0].text
        except (anthropic.InternalServerError, anthropic.APIConnectionError) as e:
            self.record_failure()
            raise


cb = CircuitBreaker(failure_threshold=5, recovery_timeout=60)

try:
    result = cb.call("Hello!")
    print(result)
except RuntimeError as e:
    print(f"Unavailable: {e}")  # Fast-fail while circuit is open
